sys_ux_client_script.script:
/**
 * @param {params} params
 * @param {api} params.api
 * @param {TransformApiHelpers} params.helpers
 */
function evaluateProperty({
    api,
    helpers
}) {
    // No reference at all means the location code is not mapped
    // to anything. This should be rare.
    if (!api.item.value.reference) return "(No Location selected)";

    // Assumes that an entry returned as valid has a good
    // reference and the label is populated
    if (api.item.value.valid) return api.item.value.reference.label;

    // We already accounted for there being no Reference
    // selected, and now we know the entry was returned as
    // invalid. This could mean one of:
    // 1. the selected Reference is invalid (label will be empty), or
    // 2. entry is invalid for other reason

    // Check for (1) and return the sys_id
    if (api.item.value.reference.label == "") {
        return api.item.value.reference.value;
    }

    return api.item.value.reference.label;
}
